const response = $input.first().json;
const text = response.content?.[0]?.text || '{}';
let meta = {};
try { meta = JSON.parse(text.match(/\{[\s\S]*\}/)?.[0] || '{}'); } catch(e) { meta = { title: 'TotalGuard Yard Care | ' + $('Parse Input').first().json.service, description: 'Professional ' + $('Parse Input').first().json.service + ' in ' + $('Parse Input').first().json.location + '. Free estimates.' }; }
return [{ json: { page_slug: $('Parse Input').first().json.page_slug, meta_title: meta.title || '', meta_description: meta.description || '', generated_at: new Date().toISOString() } }];
